INSERT INTO device (
device_id, device_name, device_type, area_id,
install_location, install_date, status,
create_time, remark
) VALUES (
#{deviceId}, #{deviceName}, #{deviceType}, #{areaId},
#{installLocation}, #{installDate}, #{status},
#{createTime}, #{remark}
)

mapper.select:
SELECT * FROM device
WHERE status = #{status}

    AND area_id = #{areaId}


    AND device_type = #{deviceType}

ORDER BY updated_time DESC

SELECT status, COUNT(*) as count FROM device WHERE 1=1
AND area_id = #{areaId}
AND device_type = #{deviceType}
GROUP BY status ORDER BY count DESC

SELECT * FROM device
WHERE area_id = #{areaId}
ORDER BY device_name

SELECT * FROM device
WHERE device_type = #{deviceType}
ORDER BY device_name

SELECT * FROM device
WHERE install_date BETWEEN #{startDate} AND #{endDate}
ORDER BY install_date DESC

SELECT device_id, updated_time
FROM device
WHERE device_id = #{deviceId}

SELECT d.* FROM device d WHERE d.status = 'offline' AND d.updated_time < DATE_SUB(NOW(), INTERVAL #{thresholdMinutes} MINUTE)
AND d.area_id = #{areaId}
ORDER BY d.updated_time ASC

mapper.insert:
INSERT INTO device (
device_id, device_name, device_type, area_id,
install_location, install_date, status,
create_time, remark
) VALUES

    (
    #{device.deviceId}, #{device.deviceName}, #{device.deviceType}, #{device.areaId},
    #{device.installLocation}, #{device.installDate}, #{device.status},
    #{device.createTime}, #{device.remark}
    )

mapper.select:
SELECT * FROM device
WHERE 1=1

    AND device_name LIKE CONCAT('%', #{deviceName}, '%')


    AND device_type = #{deviceType}


    AND status = #{status}


    AND area_id = #{areaId}


    AND install_date >= #{startDate}


    AND install_date <= #{endDate}

ORDER BY create_time DESC

SELECT d.device_id as "设备ID", d.device_name as "设备名称", d.device_type as "设备类型", a.area_name as "所属区域", d.install_location as "安装位置", d.install_date as "安装日期", d.status as "设备状态", d.create_time as "创建时间", d.updated_time as "更新时间", COUNT(DISTINCT dtm.terminal_id) as "终端数量", COUNT(DISTINCT wo.order_id) as "工单数量", COUNT(DISTINCT al.alert_id) as "告警数量" FROM device d LEFT JOIN area a ON d.area_id = a.area_id LEFT JOIN device_terminal_mapping dtm ON d.device_id = dtm.device_id LEFT JOIN work_order wo ON d.device_id = wo.device_id LEFT JOIN alert al ON d.device_id = al.device_id WHERE 1=1
AND d.area_id = #{conditions.areaId}
AND d.device_type = #{conditions.deviceType}
AND d.status = #{conditions.status}
GROUP BY d.device_id, d.device_name, d.device_type, a.area_name, d.install_location, d.install_date, d.status, d.create_time, d.updated_time ORDER BY d.create_time DESC
